// This header is normally generated by `cxxbridge` from
// `rust/workspace/rustyline/src/lib.rs`. We commit a hand-written copy
// here so that the C++ side (RustylineLineReader.cpp) can compile without
// a cxxbridge invocation in the build path. If you change the cxx bridge
// in lib.rs, regenerate this file with:
//
//     cxxbridge rust/workspace/rustyline/src/lib.rs --header > \
//         rust/workspace/rustyline/include/rustyline-lib.rs.h
//
// and audit the diff carefully — the C++ class layout (including
// IsRelocatable hints) must match what cxx generates internally for the
// static library, otherwise you'll get heap corruption at the boundary.

#pragma once

#include <cstddef>
#include <cstdint>
#include <string>
#include <vector>

#include "rust/cxx.h"  // ::rust::String, ::rust::Vec, ::rust::Box

namespace DB::rustyline
{

enum class ReadStatus : ::std::uint8_t
{
    Line = 0,
    Eof = 1,
    Interrupted = 2,
    Error = 3,
};

struct EditorOptions final
{
    ::std::uint32_t history_max_entries;
    bool ignore_shell_suspend;
    bool embedded_mode;
    bool interactive_history_legacy_keymap;
    bool enable_skim;
    bool enable_highlight;
    bool multiline;
    ::rust::String word_break_characters;

    using IsRelocatable = ::std::true_type;
};

struct CompletionEntry final
{
    ::rust::String replacement;

    using IsRelocatable = ::std::true_type;
};

struct CompletionResult final
{
    ::std::size_t start;
    ::rust::Vec<::DB::rustyline::CompletionEntry> entries;

    using IsRelocatable = ::std::true_type;
};

struct ReadResult final
{
    ::DB::rustyline::ReadStatus status;
    ::rust::String text;

    using IsRelocatable = ::std::true_type;
};

/// Opaque Rust-owned editor. Constructed via `new_editor`. Methods are
/// exposed as C++ member functions by cxxbridge.
class Editor final : public ::rust::Opaque
{
public:
    ::DB::rustyline::ReadResult read_line(const ::std::string & prompt);
    void add_history(const ::std::string & line);
    void load_history(const ::std::string & path);
    void save_history(const ::std::string & path);
    ::rust::Vec<::rust::String> history_lines() const;
    void set_preload(const ::std::string & text);
    void enable_bracketed_paste(bool on);

    /// Not constructible from C++ — always obtained as `::rust::Box<Editor>`.
    ~Editor() = delete;
};

::rust::Box<::DB::rustyline::Editor> new_editor(const ::DB::rustyline::EditorOptions & opts);
void set_last_is_delimiter(bool flag);

}
